# Data tables (the single source of truth)
# ---------------------------------------------------------------------------


@dataclass(frozen=True)
class Company:
    name: str
    founded: int
    founder: str  # must match a Person.name
    hq_city: str
    hq_country: str
    industry: str
    notable_product: str
    parent: Optional[str] = None  # name of acquiring company, if any


@dataclass(frozen=True)
class Person:
    name: str
    born: int
    birthplace: str  # "City, Country"
    alma_mater: str
    field: str  # e.g. "robotics", "biotech"


