# ---------------------------------------------------------------------------
# Templating
# ---------------------------------------------------------------------------


def _company_doc(c: Company) -> str:
    """Render a company bio with three paragraphs of factual content.

    Paragraph 1: founding facts (industry, year, founder, HQ).
    Paragraph 2: product + provenance (acquisition history if any).
    Paragraph 3: leadership + a bit of editorial prose to make the
    document feel realistic to extract from. Every claim here is
    grounded in the data tables -- nothing is invented at render time.
    """
    parent_clause = (
        f" In 2022, {c.name} was acquired by {c.parent}, deepening its "
        f"distribution reach into adjacent markets."
        if c.parent
        else ""
    )
    founder_obj = next((p for p in PEOPLE if p.name == c.founder), None)
    founder_origin = (
        f" {c.founder} originally trained at {founder_obj.alma_mater} "
        f"and brought a {founder_obj.field} background to the company."
        if founder_obj
        else ""
    )
    return (
        f"{c.name} is a {c.industry} company founded in {c.founded} by {c.founder}. "
        f"Headquartered in {c.hq_city}, {c.hq_country}, the company has grown "
        f"steadily since its founding and now serves customers across multiple "
        f"continents. {c.name} maintains research operations in {c.hq_city} as "
        f"well as a small satellite office focused on {c.industry} partnerships.\n\n"
        f"The company is best known for its flagship product, the {c.notable_product}. "
        f"The {c.notable_product} is widely deployed across the {c.industry} sector "
        f"and has been described as a turning point for the field. Industry analysts "
        f"have credited {c.name} with normalising several {c.industry} practices "
        f"that were considered experimental at the time of the {c.notable_product}'s "
        f"launch.{parent_clause}\n\n"
        f"{c.name} continues to operate from its {c.hq_city} office and is led by "
        f"{c.founder}, who serves as chief executive.{founder_origin} The company "
        f"reports continued investment in {c.industry} R&D and intends to expand "
        f"its {c.notable_product} platform over the coming years."
    )


def _person_doc(p: Person) -> str:
    """Render a person bio that anchors birthplace, education, prior
    roles, and the company they founded. Same authoring rules as
    `_company_doc` -- every fact is sourced from the data tables."""
    prior = next((r for r in PRIOR_ROLES if r[0] == p.name), None)
    prior_clause = (
        f" Earlier in their career, {p.name} served as {prior[2]} at {prior[1]}, "
        f"where they led several {p.field} initiatives that shaped their later "
        f"thinking on the field."
        if prior
        else ""
    )
    # Find the company they founded, if any.
    founded = next((c for c in COMPANIES if c.founder == p.name), None)
    founded_clause = (
        f"\n\nIn {founded.founded}, {p.name} founded {founded.name}, a "
        f"{founded.industry} company headquartered in {founded.hq_city}, "
        f"{founded.hq_country}. The company's flagship product is the "
        f"{founded.notable_product}, which has shipped to enterprise customers "
        f"across the {founded.industry} sector."
        if founded
        else ""
    )
    return (
        f"{p.name} is a {p.field} researcher and entrepreneur, born in {p.born} "
        f"in {p.birthplace}. They studied at {p.alma_mater}, where they "
        f"specialised in {p.field} and built early prototypes that later "
        f"informed their commercial work. Colleagues describe {p.name} as a "
        f"{p.field} practitioner with a hands-on approach to engineering."
        f"{prior_clause}{founded_clause}\n\n"
        f"{p.name} continues to work in {p.field} and is regarded as one of the "
        f"more visible voices in the {p.field} community originating from "
        f"{p.birthplace.split(',')[0]}."
    )


# ---------------------------------------------------------------------------
# Ground-truth queries
# ---------------------------------------------------------------------------


# Each query is (question, expected_substrings, hop_count, kind). The
# expected_substrings list is OR'd: an answer counts as correct if it
# contains ANY of them (case-insensitive). hop_count is informational --
# it tells you how many graph edges a faithful answer must traverse.
QUERIES: List[dict] = [
    # --- 1-hop: single fact lookup ---
    {
        "q": "Who founded Helix Robotics?",
        "expects": ["Maya Chen"],
        "hops": 1,
        "kind": "single_fact",
    },
    {
        "q": "What is the flagship product of QubitForge?",
        "expects": ["Forge-Q1"],
        "hops": 1,
        "kind": "single_fact",
    },
    {
        "q": "In what year was BlueCell Storage founded?",
        "expects": ["2011"],
        "hops": 1,
        "kind": "single_fact",
    },
    {
        "q": "Where is FjordWind headquartered?",
        "expects": ["Bergen"],
        "hops": 1,
        "kind": "single_fact",
    },
    # --- 2-hop: traversal across two documents ---
    {
        "q": "Where was the founder of Helix Robotics born?",
        "expects": ["Singapore"],
        "hops": 2,
        "kind": "multi_hop",
    },
    {
        "q": "Where did the founder of QubitForge study?",
        "expects": ["Cambridge"],
        "hops": 2,
        "kind": "multi_hop",
    },
    {
        "q": "What is the alma mater of the founder of Andes Imaging?",
        "expects": ["MIT"],
        "hops": 2,
        "kind": "multi_hop",
    },
    {
        "q": "Which industry is the company founded by Aiko Tanaka in?",
        "expects": ["ceramics"],
        "hops": 2,
        "kind": "multi_hop",
    },
    # --- 3-hop: cross multiple entity types ---
    {
        "q": "What was the prior employer of the founder of AtlasFlow?",
        "expects": ["PalmPay Africa", "PalmPay"],
        "hops": 3,
        "kind": "multi_hop",
    },
    {
        "q": "Which company acquired KattegatWind, and who founded that acquiring company?",
        "expects": ["FjordWind", "Ingrid Larsen"],
        "hops": 3,
        "kind": "multi_hop",
    },
    # --- aggregation / set ---
    {
        "q": "Name a company headquartered in Milan.",
        "expects": ["CargoMesh", "Pellegrino"],
        "hops": 1,
        "kind": "aggregation",
    },
    {
        "q": "Which company is best known for the EdgeMint Box?",
        "expects": ["EdgeMint"],
        "hops": 1,
        "kind": "single_fact",
    },
]


# ---------------------------------------------------------------------------
# Materialisation
# ---------------------------------------------------------------------------


def materialise(
    corpus_dir: Path = OUT_CORPUS_DIR, queries_path: Path = OUT_QUERIES
) -> dict:
    """Write the corpus and query set to disk and return a stats dict.

    Idempotent: existing files are overwritten so re-running gives a
    clean slate without leftover docs from a previous experiment.
    """
    corpus_dir.mkdir(parents=True, exist_ok=True)
    # Wipe stale documents so adding/removing data tables stays honest.
    for old in corpus_dir.glob("*.txt"):
        old.unlink()

    word_count = 0
    n_docs = 0
    for c in COMPANIES:
        text = _company_doc(c)
        slug = c.name.lower().replace(" ", "_")
        (corpus_dir / f"company_{slug}.txt").write_text(text + "\n", encoding="utf-8")
        word_count += len(text.split())
        n_docs += 1
    for p in PEOPLE:
        text = _person_doc(p)
        slug = p.name.lower().replace(" ", "_").replace(",", "")
        (corpus_dir / f"person_{slug}.txt").write_text(text + "\n", encoding="utf-8")
        word_count += len(text.split())
        n_docs += 1

    queries_path.write_text(json.dumps(QUERIES, indent=2), encoding="utf-8")

    return {
        "documents": n_docs,
        "words": word_count,
        "approx_tokens": int(word_count * 1.3),  # rough heuristic
        "queries": len(QUERIES),
        "corpus_dir": str(corpus_dir),
        "queries_path": str(queries_path),
    }


if __name__ == "__main__":
    stats = materialise()
    print(json.dumps(stats, indent=2))
